@app.route('/login', methods=['POST'])
def login():
    auth = request.authorization    # get username and password from basic authorization header
  
    if not auth or not auth.username or not auth.password:  
        return jsonify({"message": "Invalid credentials!"}), 401
    
    user = {"admin":"pass"}   # mock users database
     
